INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Unified free CRM$q$, $q$Contact, company, and deal records shared across marketing, sales, and service teams at no cost for unlimited users.$q$, 0);
