INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Sales pipeline management$q$, $q$Deal stages, sequences, quotes, and forecasting tools in Sales Hub.$q$, 2);
