INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Reporting and dashboards$q$, $q$Cross-Hub custom dashboards combining marketing, sales, and service data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$App marketplace and integrations$q$, $q$Over 1,700 third-party integrations plus a public API for custom connections.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Free CRM tier is genuinely usable for unlimited users, not just a trial$q$, 0);
