INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Costs escalate quickly once multiple Hubs and Professional/Enterprise tiers are needed$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Onboarding fees on higher tiers add significant upfront cost$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Contact-based pricing can penalize businesses with large but low-value contact lists$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Advanced customization is less flexible than Salesforce for complex enterprise workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Some advanced automation and reporting features are locked behind expensive tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Is HubSpot free to use?$q$, $q$Yes. HubSpot CRM is permanently free for unlimited users, including basic contact management, email tracking, forms, and live chat. Paid plans add automation, custom reporting, and higher usage limits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Who founded HubSpot and when?$q$, $q$HubSpot was founded in 2006 by Brian Halligan and Dharmesh Shah, who met at the MIT Sloan School of Management and built the company around inbound marketing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$How much does HubSpot cost?$q$, $q$Pricing ranges from free (CRM) to roughly 20 dollars per seat per month for Starter, 100-890 dollars per month for Professional depending on the Hub, and 150 dollars per seat up to several thousand dollars per month for Enterprise bundles.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$What is the difference between HubSpot and HubSpot CRM?$q$, $q$HubSpot CRM is the free contact and deal management core; 'HubSpot' refers to the full customer platform, which layers paid Marketing, Sales, Service, CMS, Operations, and Commerce Hubs on top of that free CRM.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$What are the main HubSpot alternatives?$q$, $q$Common alternatives include Salesforce for enterprise-grade CRM customization, ActiveCampaign and Mailchimp for lower-cost marketing automation, and Zoho CRM or Pipedrive for simpler, cheaper sales-focused CRMs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Is HubSpot a public company?$q$, $q$Yes. HubSpot has traded on the New York Stock Exchange under the ticker HUBS since its 2014 IPO and is headquartered in Cambridge, Massachusetts.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Inbound marketing and lead generation$q$, $q$Marketing teams build landing pages, blog content, and automated nurture campaigns to attract and convert website visitors into tracked leads.$q$, $q$Marketing teams at small and mid-sized B2B companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Unified sales pipeline management$q$, $q$Sales reps track deals, automate follow-up sequences, and send quotes without leaving the same record customers interact with in support.$q$, $q$Sales teams and revenue operations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Customer support and retention$q$, $q$Support teams manage tickets, publish a self-service knowledge base, and track satisfaction, all tied to the same customer history as sales and marketing.$q$, $q$Customer service and success teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Free CRM$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited users","Contact and deal records","Email tracking and scheduling","Live chat and forms","Basic reporting dashboard"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Starter$q$, $q$From $20/seat/month (from $15/seat/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["No HubSpot branding","Basic marketing automation","Multiple deal pipelines","Simple reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Professional$q$, $q$From $100/seat/month (Sales/Service); from $890/month for 3 seats (Marketing)$q$, $q$monthly or annual$q$, NULL, $q$["Marketing automation workflows","Custom reports and dashboards","A/B testing and personalization","Team permissions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$Enterprise$q$, $q$From $150/seat/month (Sales/Service); from $3,600/month (Marketing/bundled Customer Platform)$q$, $q$monthly or annual$q$, NULL, $q$["Custom objects","Advanced permissions and sandboxes","Hierarchical teams","Enterprise-grade AI features"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HubSpot began as a bet on 'inbound marketing' -- the idea that companies should earn attention through useful content and SEO rather than buying it through interruptive ads. Brian Halligan and Dharmesh Shah founded the company in 2006 out of MIT, and it has since grown from a marketing blog tool into a full customer platform spanning marketing, sales, service, content management, commerce, and operations, all sharing one CRM record for every contact and company.$q$, $q$The platform's core architectural decision -- giving away HubSpot CRM for free and monetizing the automation, reporting, and AI layered on top -- has shaped its go-to-market ever since. Small teams can run entirely on the free tier, while growing companies gradually add paid Hubs as their marketing, sales, or support operations mature, without needing to migrate data between disconnected systems.$q$, $q$HubSpot is publicly traded (NYSE: HUBS) and headquartered in Cambridge, Massachusetts, with a global workforce and a large partner and agency ecosystem that implements and customizes the platform for customers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Marketing Hub covers email marketing, landing pages, SEO recommendations, ad management, and multi-step automation workflows. Sales Hub adds deal pipelines, email sequences, meeting scheduling, quotes, and forecasting, while Service Hub handles ticketing, a knowledge base, live chat, and customer satisfaction surveys -- all built on the same contact timeline so reps and support agents see a complete history of every interaction.$q$, $q$CMS Hub lets marketing teams build and host websites with drag-and-drop modules, adaptive testing, and built-in technical SEO tooling, and Operations Hub keeps third-party data in sync and clean through automation and data quality rules. Across every Hub, HubSpot has added generative AI features under its Breeze branding, including a content assistant, an AI chatbot/agent builder, and predictive lead scoring.$q$, $q$Reporting is centralized in customizable dashboards that pull from marketing, sales, and service data simultaneously, which is one of HubSpot's most cited advantages over stitching together point solutions for each function.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8af9c066-32c1-4f6a-8dc1-50233b5e3a3b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HubSpot CRM itself remains free for unlimited users, covering contact records, deal tracking, email tracking, forms, and live chat. Paid plans start with Starter (roughly 15-20 dollars per seat per month) which removes HubSpot branding and unlocks basic automation, scale into Professional (100 dollars per seat per month for Sales or Service Hub, or around 890 dollars per month for a 3-seat Marketing Hub Professional bundle) for marketing automation and custom reporting, and top out at Enterprise (150+ dollars per seat per month, or up to roughly 3,600-4,300 dollars per month for bundled Customer Platform editions) for custom objects, advanced permissions, and enterprise AI features.$q$, $q$Costs scale with both seats and contacts, and Professional/Enterprise tiers often carry a mandatory one-time onboarding fee (commonly 3,000 dollars for Marketing Hub Professional). Because pricing compounds quickly across multiple Hubs, most reviewers recommend starting on the free CRM or Starter tier and upgrading only the specific Hub that a team has outgrown.$q$]::text[], 2);
