INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Less configurable than Salesforce for complex, custom sales processes$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Is HubSpot CRM really free?$q$, $q$Yes. The core CRM -- contacts, deals, email tracking, forms, and live chat -- is free indefinitely for unlimited users, not a limited-time trial.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$How is HubSpot CRM different from full HubSpot?$q$, $q$HubSpot CRM is the free contact and deal management foundation. 'HubSpot' more broadly refers to the paid Marketing, Sales, Service, CMS, and Operations Hubs built on top of that same CRM data.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$What does HubSpot CRM cost after the free tier?$q$, $q$Starter begins around 15-20 dollars per seat per month, Professional around 100 dollars per seat per month, and Enterprise from about 150 dollars per seat per month, depending on which Hub is added.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Can I import existing contacts into HubSpot CRM?$q$, $q$Yes, HubSpot CRM supports CSV imports and native integrations with Gmail, Outlook, and many other tools to bring in existing contact and deal data.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Does HubSpot CRM work on mobile?$q$, $q$Yes, HubSpot offers iOS and Android apps that let sales reps view records, log calls, and manage tasks from their phone.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$What are alternatives to HubSpot CRM?$q$, $q$Popular free or low-cost alternatives include Zoho CRM, Pipedrive, Freshsales, and monday CRM, though each has different limits on users, contacts, or automation compared to HubSpot's free tier.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Replacing spreadsheets for deal tracking$q$, $q$Small sales teams move from spreadsheets to a shared pipeline with reminders and email tracking at no cost.$q$, $q$Small businesses and startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Centralizing customer records for growing teams$q$, $q$Mid-sized teams use the free CRM as the single source of truth before layering on paid marketing or service automation.$q$, $q$Growing SMBs and scaleups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Sales rep productivity$q$, $q$Individual reps track email opens, schedule meetings, and manage follow-up tasks directly from their inbox.$q$, $q$Sales representatives and account managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited users","Contact and deal records","Email tracking and scheduling","Live chat and forms","Meeting scheduling"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Starter$q$, $q$From $20/seat/month (from $15/seat/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["No HubSpot branding","Basic automation","Additional pipelines","Simple reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Professional$q$, $q$From $100/seat/month$q$, $q$monthly or annual$q$, NULL, $q$["Sales sequences and playbooks","Custom reporting and forecasting","Advanced automation","Team permissions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$Enterprise$q$, $q$From $150/seat/month$q$, $q$monthly or annual$q$, NULL, $q$["Custom objects","Advanced permissions and sandboxes","Predictive lead scoring","Hierarchical teams"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HubSpot CRM is the free, foundational product inside HubSpot's broader customer platform. Launched in 2014 as a deliberate lead-generation strategy, it gives unlimited users a shared system of record for contacts, companies, and deals at no cost, with HubSpot instead charging for the marketing, sales, and service automation that can later be layered on top.$q$, $q$Because it runs on the same database as HubSpot's paid Hubs, businesses that start on the free CRM never have to migrate data when they eventually add Marketing Hub, Sales Hub, or Service Hub -- contact history, deal notes, and email tracking carry forward automatically, which is a key differentiator versus free tiers from competing CRM vendors that require a rip-and-replace migration to unlock automation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The free plan includes contact and company records, a visual deal pipeline, task and activity reminders, email tracking and scheduling, meeting scheduling, live chat, and customizable forms, all accessible to unlimited users with no seat limit. A Chrome extension and mobile app let sales reps log activity and track emails from Gmail or Outlook without leaving their inbox.$q$, $q$Paid tiers progressively add automation (Starter), custom reporting, forecasting, and sales sequences (Professional), and custom objects with advanced permissioning and predictive scoring (Enterprise) -- all built as extensions of the same CRM object rather than a separate product.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HubSpot CRM's core functionality -- contact records, deal pipelines, email tracking, and unlimited users -- remains free indefinitely, with no trial expiration. Businesses only start paying when they need HubSpot branding removed, more automated workflows, or additional Sales/Service Hub features.$q$, $q$From there, Starter runs roughly 15-20 dollars per seat per month, Professional (as Sales Hub or Service Hub Professional) runs about 100 dollars per seat per month, and Enterprise starts around 150 dollars per seat per month, all billed per user with annual billing offering a discount over month-to-month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ef29f747-f15c-4d08-991c-1e5c8ee38641', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
