INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Automatic time tracking$q$, $q$One-click timers across desktop, mobile, and Chrome extension synced in real time to projects and tasks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Screenshots and activity monitoring$q$, $q$Optional, configurable screenshots plus keyboard/mouse activity levels and app/URL usage tracking.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$GPS and geofencing$q$, $q$Mobile location tracking that auto-starts and stops timers when field workers enter a job-site radius.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Integrated payroll$q$, $q$Direct payments through PayPal, Wise, Deel, Payoneer, and Gusto generated from approved timesheets.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Project budgeting$q$, $q$Track cost against tracked time to keep client and internal projects on budget.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Automated timesheets and approvals$q$, $q$Timesheets generated automatically with configurable manager approval workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Invoicing$q$, $q$Generate client invoices directly from tracked and approved billable hours.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Third-party integrations$q$, $q$Connects with Trello, Asana, QuickBooks, Slack, and other project and accounting tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Combines time tracking, activity monitoring, GPS, and payroll in one product$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Flexible monitoring settings let teams choose how much oversight to apply$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Native payroll disbursement through multiple payment providers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$GPS geofencing is well suited to field and construction teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Detailed reporting on productivity, budgets, and billable hours$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Two-seat minimum on paid plans adds cost for solo users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Screenshot and activity monitoring can feel invasive to employees if not communicated well$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Higher tiers needed to unlock GPS, payroll, and advanced reporting$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Interface can feel dense for teams that only need basic time tracking$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Per-seat pricing scales up quickly for larger teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Who founded Hubstaff and when?$q$, $q$Hubstaff was founded in 2012 in Indianapolis, Indiana by Dave Nevogt and Jared Brown, who built it to manage their own remote and freelance workers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Does Hubstaff have a free plan?$q$, $q$Yes, Hubstaff offers a limited free plan for a single user; paid plans require a minimum of two seats.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$How much does Hubstaff cost?$q$, $q$Paid plans range from roughly 7 dollars per seat per month (Starter) up to about 25 dollars per seat per month (Enterprise), with lower rates available on annual billing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Does Hubstaff take screenshots of employees?$q$, $q$Screenshot capture is optional and configurable; teams can enable or disable it and set the frequency, and Hubstaff also tracks keyboard/mouse activity levels and app usage as separate optional settings.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Can Hubstaff track field workers with GPS?$q$, $q$Yes, the mobile app supports GPS tracking and geofencing that can automatically start or stop timers when a worker enters or leaves a defined job-site radius.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Does Hubstaff process payroll?$q$, $q$Yes, Hubstaff can pay team members directly from approved timesheets through PayPal, Wise, Deel, Payoneer, or Gusto.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Remote team time tracking$q$, $q$Distributed companies track hours, monitor productivity, and pay contractors accurately without manual timesheets.$q$, $q$Remote-first companies and digital agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Field service and construction workforce management$q$, $q$GPS geofencing verifies that hourly workers were on-site while timers ran, reducing time theft on job sites.$q$, $q$Construction, field service, and logistics teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Client billing and project profitability$q$, $q$Agencies track billable hours against project budgets and generate client invoices directly from tracked time.$q$, $q$Agencies and consulting firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1 user","Basic time tracking","Limited reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Starter$q$, $q$$7/seat/month ($4.99/seat/month billed annually)$q$, $q$monthly or annual, 2-seat minimum$q$, NULL, $q$["Time tracking","Basic reporting","Limited integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Grow$q$, $q$$9/seat/month ($7.50/seat/month billed annually)$q$, $q$monthly or annual, 2-seat minimum$q$, NULL, $q$["Screenshots and activity levels","Project budgets","More integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Team$q$, $q$$12/seat/month ($10/seat/month billed annually)$q$, $q$monthly or annual, 2-seat minimum$q$, NULL, $q$["GPS tracking and geofencing","Payroll integration","Advanced reporting"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hubstaff grew out of a personal problem: founders Dave Nevogt and Jared Brown were managing freelance and remote workers in 2012 and couldn't find software that reliably tracked hours and productivity across a distributed team, so they built their own. Based in Indianapolis, the company has since scaled to serve tens of thousands of organizations that need to track time, monitor activity, and pay distributed workers without relying on the honor system.$q$, $q$The product spans desktop, mobile, and browser clients, all feeding a central dashboard that combines timesheets, screenshots, activity levels, GPS data, and payroll in one place -- positioning Hubstaff as much a workforce management suite as a pure time tracker.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Automatic time tracking runs across desktop, mobile, and a Chrome extension, syncing one-click timers to specific projects and tasks in real time. Optional activity monitoring captures screenshots at configurable intervals along with keyboard/mouse activity levels and app or URL usage, giving managers visibility into how tracked time was spent -- a feature that can be disabled per team for organizations that prefer lighter-touch tracking.$q$, $q$For field teams, GPS tracking and geofencing let the mobile app automatically start and stop timers when workers enter or leave a defined job-site radius. Hubstaff also handles the operational side of workforce management: project budgets that track cost against time, automated timesheets with manager approval workflows, client invoicing generated from billed hours, and integrated payroll that pays teams directly through PayPal, Wise, Deel, Payoneer, or Gusto.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hubstaff prices per seat with a two-seat minimum on every paid plan except Enterprise. Starter costs roughly 7 dollars per seat per month (about 4.99 dollars billed annually), Grow runs about 9 dollars per seat per month (roughly 7.50 annually), and Team costs about 12 dollars per seat per month (roughly 10 dollars annually), each tier unlocking more automation, integrations, and reporting depth.$q$, $q$Enterprise is priced around 25 dollars per seat per month with expanded controls, priority support, and advanced reporting for larger organizations. A limited single-user Free plan exists for individuals, and annual billing across all tiers typically works out to roughly two months free compared to paying monthly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
