INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
