INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Zot protocol identity$q$, $q$Decentralized identity and access-control framework with fine-grained, extensible permissions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Nomadic identity$q$, $q$Clone a channel across multiple hubs so identity and content are not locked to one server.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Social networking$q$, $q$Activity streams, wall posts, comments, private messaging, and groups.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Website and CMS tools$q$, $q$Build and publish full websites and articles directly from a hub.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$File and photo storage$q$, $q$Upload, organize, and share files and photo albums with granular permissions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Forums and wikis$q$, $q$Host discussion groups and collaborative wiki pages within the same platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Multi-protocol federation$q$, $q$Interoperates with ActivityPub, Diaspora, DFRN, and OStatus networks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Self-hosting and single sign-on$q$, $q$Run your own hub and authenticate seamlessly across every hub in the grid.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Completely free, open-source, and self-hostable with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Unique nomadic identity lets users move or clone their account across hubs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Combines social networking, CMS, file sharing, and wikis in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Fine-grained, per-connection permission controls uncommon in other federated tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Interoperates with the wider Fediverse via ActivityPub and other protocols$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Requires self-hosting and technical administration; no simple signup for most users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Steeper learning curve than single-purpose tools like Mastodon$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Smaller, more niche user base than mainstream Fediverse platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Documentation and UI feel dated compared to modern social apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Development pace and community size are modest, so feature updates can be slow$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$What is Hubzilla?$q$, $q$Hubzilla is a free, open-source platform combining social networking, a CMS, file sharing, forums, and wikis, run on self-hosted servers called hubs that federate together into a decentralized network.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Who created Hubzilla?$q$, $q$Hubzilla descends from Mike Macgirvin's earlier Mistpark and Friendica projects; he forked it in 2012 to build the Zot protocol, which evolved into Hubzilla before he handed project coordination to the community in 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Is Hubzilla free to use?$q$, $q$Yes, the software is free and open source under the AGPLv3 license. The only cost is hosting your own server or finding a hub operator willing to host your account.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$What is nomadic identity in Hubzilla?$q$, $q$Nomadic identity, powered by the Zot protocol, lets a user clone their channel, content, and connections across multiple hubs so their identity is not tied to a single server.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Does Hubzilla work with Mastodon?$q$, $q$Yes, Hubzilla supports the ActivityPub protocol among others, allowing it to federate with Mastodon and other Fediverse platforms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$How is Hubzilla different from Friendica?$q$, $q$Both share the same creator and lineage, but Hubzilla adds broader CMS, file-sharing, wiki, and nomadic-identity capabilities, while Friendica remains more narrowly focused on social networking.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Privacy-conscious community hosting$q$, $q$Groups run their own hub to control data, moderation, and permissions instead of relying on a centralized platform.$q$, $q$Privacy-focused communities and organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Portable online identity$q$, $q$Users who want their social identity and content independent of any single server host or clone their channel across hubs.$q$, $q$Fediverse users and decentralization advocates$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Combined website and social presence$q$, $q$Individuals or small organizations use one hub to publish a website, share files, and run a social feed together.$q$, $q$Developers, hobbyists, and small self-hosted communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$Self-hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code and all features","Run on your own server or VPS","Unlimited hubs and channels","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hubzilla is open-source software that individuals or organizations install on their own server, called a 'hub,' which then federates with other independently run hubs to form a decentralized network its community calls 'the grid.' It descends from Mike Macgirvin's earlier project Mistpark and its successor Friendica, forked in 2012 to explore a new decentralized identity system that eventually became the Zot protocol and, ultimately, Hubzilla.$q$, $q$Unlike most social platforms, Hubzilla is not a single service you sign up for -- it is software you (or a hub operator you trust) run yourself, and there is no central company or SaaS offering behind it. Development is community-driven and released under the AGPLv3 open-source license.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core is the Zot protocol, which handles decentralized identity, cross-hub authentication, and fine-grained permissions. This enables 'nomadic identity': a user's channel, including their content, connections, and permissions, can be cloned across multiple hubs, so the account is not permanently tied to any single server the way most federated platforms bind you to your home instance.$q$, $q$Beyond social networking (activity streams, wall posts, groups, private messaging), Hubzilla doubles as a lightweight CMS for building websites, a file and photo storage/sharing tool, a forum and wiki host, and a calendar/events system, all reachable through a single sign-on across every hub a user's identity touches. For federation beyond the Zot-native grid, Hubzilla speaks ActivityPub, Diaspora, DFRN, and OStatus, letting it interoperate with Mastodon and other Fediverse software.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hubzilla itself is free, open-source software with no licensing cost. There is no official hosted plan or subscription tier from a central vendor; instead, users either run their own hub on a VPS or dedicated server, or join a hub operated by a volunteer or community that offers accounts.$q$, $q$The only real cost is server hosting, which for a small hub typically runs a few dollars to a few tens of dollars per month depending on storage, bandwidth, and traffic, plus the time required for a technically capable administrator to install, configure, and maintain the software.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
