INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a66fca94-72b5-448d-a986-f5944ee873d8', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Extremely fast builds$q$, $q$Compiles to a native Go binary, regenerating sites with tens of thousands of pages in seconds.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Multilingual support$q$, $q$Per-language content trees and i18n translation bundles built into core.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Built-in image processing$q$, $q$Resize, crop, and convert images at build time without external tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Asset pipeline$q$, $q$Bundle, minify, and fingerprint CSS and JavaScript as part of the build.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Custom output formats$q$, $q$Render the same content as HTML, JSON, RSS, or AMP from one source.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Markdown render hooks and shortcodes$q$, $q$Customize how Markdown elements render and embed reusable content snippets.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Live-reload dev server$q$, $q$Local server with instant preview while authoring content and templates.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$No dependencies to install$q$, $q$Ships as a single self-contained binary with no external runtime required.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Very fast build times even for large sites with thousands of pages$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Single binary with no runtime dependencies to install or manage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Extensive built-in features (i18n, image processing, asset pipeline) with no plugins needed$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Completely free, open source, and actively maintained by a large community$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Deploys easily to any static host or CDN with no server required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$No built-in CMS or admin UI, so non-technical editors need a separate headless CMS$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Go templating syntax has a steeper learning curve than some competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$No official commercial support; help comes from community forums and documentation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Less flexible for highly dynamic, component-based UI compared to React-based generators$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Some advanced customizations require understanding Go template functions$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Is Hugo free to use?$q$, $q$Yes, Hugo is completely free and open source under the Apache 2.0 license, with no paid tiers or licensing fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Who created Hugo?$q$, $q$Steve Francia created Hugo in 2013; Bjørn Erik Pedersen has led development since 2015, alongside a large open-source contributor community.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Does Hugo require a database?$q$, $q$No, Hugo generates static HTML, CSS, and JavaScript files at build time, so deployed sites need no database or server-side application.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$What programming language is Hugo written in?$q$, $q$Hugo is written in Go, which is a key reason it compiles sites significantly faster than interpreted-language generators like Jekyll (Ruby) or Gatsby (JavaScript).$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Can Hugo build multilingual websites?$q$, $q$Yes, Hugo has built-in multilingual support with per-language content trees and translation bundles, no plugins required.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$What are the main alternatives to Hugo?$q$, $q$Common alternatives include Jekyll, Eleventy (11ty), Gatsby, Astro, and Next.js in static export mode, each with different tradeoffs around speed, templating language, and CMS integration.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Documentation sites$q$, $q$Teams build fast, versioned technical documentation sites that regenerate quickly even with thousands of pages.$q$, $q$Developer relations and documentation teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Blogs and personal websites$q$, $q$Writers and developers publish Markdown-based blogs with fast builds and simple Git-based deployment.$q$, $q$Individual developers and technical writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Marketing and company websites$q$, $q$Companies pair Hugo with a headless CMS to give marketing teams an editing interface while keeping the frontend static and fast.$q$, $q$Marketing teams and web agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source and all features","Unlimited sites and pages","Community support via forums and docs","Apache 2.0 license"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hugo is an open-source static site generator written in Go, created by Steve Francia in 2013 and led since 2015 by Bjørn Erik Pedersen and a large community of contributors. It compiles Markdown content, templates, and assets into plain static HTML, CSS, and JavaScript with no database or server-side runtime required.$q$, $q$Hugo's headline feature is raw build speed: because it compiles to a native binary in Go rather than running on an interpreted language runtime, it can regenerate sites with tens of thousands of pages in a few seconds, a benchmark it is frequently cited for against Jekyll, Gatsby, and other generators.$q$, $q$As a community-maintained open-source project with no company or funding behind it, Hugo has no official pricing, support contracts, or SaaS offering -- it is distributed as a single self-contained binary under the Apache 2.0 license and installed locally or in CI/CD pipelines.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hugo supports multilingual sites with per-language content trees and translation bundles, built-in image processing for resizing and format conversion without external tools, and an asset pipeline for bundling, minifying, and fingerprinting CSS and JavaScript. Custom output formats let the same content render as HTML, JSON, RSS, or AMP from one source.$q$, $q$Content authors can use Markdown render hooks to customize how specific elements (links, images, headings) render, and shortcodes to embed reusable components inside otherwise plain Markdown files. A built-in local development server with live reload speeds up the authoring workflow, and Hugo integrates cleanly with Git-based Jamstack deployment pipelines on hosts like Netlify, Vercel, and Cloudflare Pages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hugo itself is completely free and open source, with no paid tiers, licenses, or support contracts from a central vendor. Anyone can download the binary and use it for unlimited personal or commercial projects under the Apache 2.0 license.$q$, $q$The practical costs of running a Hugo site come entirely from optional third-party services: static hosting (many providers such as Netlify, Vercel, GitHub Pages, and Cloudflare Pages offer free tiers for typical Hugo sites), a domain name, and an optional headless CMS for non-technical content editors.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a46d19fe-50a3-4df2-8764-c03c06ff332b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
