INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Issue and task tracking$q$, $q$Customizable workflows and statuses for managing software and product development work.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Team planner$q$, $q$Centralized calendar view with time-blocking across all team tasks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Docs and knowledge base$q$, $q$Collaborative document editor linked directly to projects and issues.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Built-in chat$q$, $q$Direct messages and group channels without needing a separate messaging tool.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Virtual office / video rooms$q$, $q$Native audio and video conferencing rooms built into the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$GitHub two-way sync$q$, $q$Sync issues and pull requests bidirectionally with GitHub repositories.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Self-hosting via Docker Compose$q$, $q$Deploy the full open-source stack on your own infrastructure for free.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Unlimited users and objects$q$, $q$All plans, including the free tier, support unlimited users and unlimited tracked objects.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Fully open source and self-hostable at no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Combines issue tracking, docs, chat, and video in one connected tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Unlimited users and objects on every plan, including free$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Flat monthly pricing on hosted tiers rather than per-seat fees$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Native GitHub integration for two-way issue and PR sync$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Self-hosting requires meaningful infrastructure (recommended 16 GB RAM) and DevOps knowledge$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Smaller company and community than Linear, Jira, or Notion$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Hosted cloud availability has been in flux as the company shifts focus toward self-hosting$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$UI and feature depth in each module (docs, chat, video) can lag best-in-class single-purpose tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Documentation and third-party integration ecosystem are less mature than larger competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Is Huly free?$q$, $q$Yes, self-hosting the full open-source platform is free. A hosted cloud version also offers a free Common tier alongside paid Rare, Epic, and Legendary plans.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Who founded Huly?$q$, $q$Huly is built by Hardcore Engineering Inc., founded by CEO Andrey Platov.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Can I self-host Huly?$q$, $q$Yes, the full Huly Platform is open source under EPL-2.0 and can be self-hosted via Docker Compose, with recommended minimums of 4+ vCPUs and 16 GB RAM for production use.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$What does Huly replace?$q$, $q$Huly is positioned as an all-in-one alternative to using Linear, Jira, Slack, Notion, and Motion separately, combining issue tracking, docs, chat, and video in one platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$How much do Huly's paid plans cost?$q$, $q$Hosted plans run from a free Common tier up to roughly 19.99, 99.99, and 399.99 dollars per month for the Rare, Epic, and Legendary tiers respectively, priced flat rather than per seat.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Does Huly integrate with GitHub?$q$, $q$Yes, Huly offers native two-way synchronization of issues and pull requests with GitHub repositories.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Software development project management$q$, $q$Engineering teams track issues, sprints, and pull requests in one tool tied directly to docs and chat.$q$, $q$Software development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Startup all-in-one workspace$q$, $q$Small teams replace several separate SaaS subscriptions (issue tracker, docs, chat, video) with one connected platform.$q$, $q$Startups and small product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Self-hosted, privacy-conscious deployments$q$, $q$Organizations that must keep data on their own infrastructure self-host the full open-source stack.$q$, $q$Privacy- and compliance-conscious organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Common$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["10 GB storage","10 GB video/audio traffic","Unlimited users","Unlimited objects"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Rare$q$, $q$$19.99/month$q$, $q$monthly, flat rate$q$, NULL, $q$["100 GB storage","100 GB video/audio traffic","Unlimited users","Unlimited objects"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Epic$q$, $q$$99.99/month$q$, $q$monthly, flat rate$q$, NULL, $q$["1 TB storage","500 GB video/audio traffic","Unlimited users","Unlimited objects"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$Legendary$q$, $q$$399.99/month$q$, $q$monthly, flat rate$q$, NULL, $q$["10 TB storage","2 TB video/audio traffic","Unlimited users","Unlimited objects"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Huly is an open-source project management platform built by Hardcore Engineering Inc., founded by CEO Andrey Platov, designed to replace the combination of Linear, Jira, Notion, Slack, and Motion with a single connected workspace. Rather than being a narrow issue tracker, Huly bundles task management, documents, chat, and video conferencing into one product with a shared data model.$q$, $q$The platform is fully open source under the EPL-2.0 license, and the codebase is publicly maintained on GitHub. Teams can either self-host the full stack via Docker Compose or, where available, use a managed cloud offering, giving organizations flexibility between owning their infrastructure and using a hosted service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Huly's issue tracker supports customizable workflows and statuses similar to Linear or Jira, paired with a team planner that shows a centralized calendar with time-blocking for tasks across a team. A built-in knowledge base and rich-text document editor supports collaborative writing linked directly to issues and projects.$q$, $q$Communication is native rather than bolted on: Huly includes direct and group messaging channels plus audio/video rooms for a 'virtual office' experience, and integrates with GitHub for two-way issue and pull request sync, along with Gmail and Google Calendar connections.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting Huly is entirely free since the full platform is open source; the only cost is the infrastructure (recommended 4+ vCPUs and 16 GB RAM) needed to run its CockroachDB, Elasticsearch, Redpanda, and MinIO-based stack via Docker Compose.$q$, $q$Where a managed cloud plan is offered, pricing runs from a free Common tier (10 GB storage/traffic) through Rare (about 19.99 dollars/month, 100 GB), Epic (about 99.99 dollars/month, 1 TB), and Legendary (about 399.99 dollars/month, 10 TB), with every tier including unlimited users and unlimited tracked objects, differing mainly in storage and video/audio traffic allowances rather than per-seat fees.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9c31b644-e9f8-4a6c-b3aa-e7960053e0dc', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
