INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Employee people directory$q$, $q$Central system of record for employee data, profiles, and documents.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Absence and timesheet tracking$q$, $q$Manage time off requests, balances, and timesheets in one place.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Onboarding and offboarding automation$q$, $q$Triggerable workflows that assign tasks across HR, IT, and managers as employees join or leave.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Org chart and headcount reporting$q$, $q$Visualize reporting lines and track headcount and compensation trends.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Custom workflows and permission roles$q$, $q$Model company-specific HR processes without custom development.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Athena AI agents$q$, $q$Agentic AI layer for natural-language workflow building and automated HR request triage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Integrations and API$q$, $q$Connects with Google Workspace, Microsoft 365, Slack, Okta, DocuSign, Greenhouse, and Lattice, plus a public API.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Rewards marketplace$q$, $q$Built-in benefits and perks marketplace for employees.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Modern, consumer-grade interface compared to legacy HR software$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Highly configurable custom fields, roles, and workflows without code$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Strong API and integration ecosystem for connecting to other HR/IT tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Automated onboarding/offboarding workflows reduce manual admin work$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$New Athena AI layer adds automation on top of core HR data$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Growth and Enterprise pricing is custom-quoted and not transparent upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Smaller company than incumbents like BambooHR or Workday, so support scale may vary$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Not a full payroll or ATS replacement; often used alongside other HR point solutions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Advanced permissioning and SSO are locked behind Enterprise tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Best suited to companies already comfortable configuring workflows themselves$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$What is Humaans?$q$, $q$Humaans is a cloud-based HR information system (HRIS) that centralizes employee data and automates onboarding, offboarding, absence tracking, and other people-operations workflows for growing companies.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Who founded Humaans?$q$, $q$Humaans was founded in London in 2019 by CEO Giovanni Luperti and Karolis Narkevicius, and went through Y Combinator before raising a seed and Series A round in 2021 totaling roughly 20 million dollars.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$How much does Humaans cost?$q$, $q$The Starting Up plan begins around 7 dollars per seat per month; Growth and Enterprise plans use custom, sales-assisted pricing based on company size and requirements.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Does Humaans handle payroll?$q$, $q$Humaans is primarily an HR system of record rather than a payroll processor, but it integrates with payroll, ATS, and other HR tools via its API and app integrations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$What is Athena in Humaans?$q$, $q$Athena is Humaans' agentic AI layer, offering pre-built AI agents, natural-language automation building, and intelligent triaging of employee HR requests.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$What are alternatives to Humaans?$q$, $q$Common alternatives include BambooHR, Personio, HiBob, Workday, and Rippling, each with different tradeoffs in pricing, configurability, and enterprise readiness.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Employee data centralization$q$, $q$People teams replace spreadsheets with a single, structured system of record for employee data and documents.$q$, $q$HR and People Operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Onboarding and offboarding automation$q$, $q$Automated workflows ensure new hires and departing employees move through consistent, trackable processes.$q$, $q$HR teams and hiring managers at scale-ups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Headcount and compensation reporting$q$, $q$Leadership tracks real-time headcount, org structure, and compensation trends through built-in analytics.$q$, $q$People analytics and finance leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Starting Up$q$, $q$From $7/seat/month$q$, $q$monthly or annual$q$, NULL, $q$["People directory","Document management","Absence tracking","Timesheets"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Growth$q$, $q$Custom pricing$q$, $q$annual, custom quote$q$, NULL, $q$["Workflow automation","Onboarding and offboarding automation","Up to 2 custom permission roles","Insights, analytics, and automated reports","API access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual, custom quote$q$, NULL, $q$["SAML SSO (Okta, Entra ID)","Unlimited custom permission roles and fields","Webhooks and audit log export","Dedicated sandbox and customer success manager","99.9% uptime guarantee"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Humaans is a cloud-based HR information system founded in London in 2019 by CEO Giovanni Luperti and Karolis Narkevicius, aimed at giving growing companies a modern, consumer-grade alternative to legacy HR software. The company went through Y Combinator and raised roughly 20 million dollars across seed and Series A rounds in 2021 to build out the platform.$q$, $q$Rather than trying to be an all-in-one payroll or ATS suite, Humaans positions itself as the flexible system of record for employee data that other HR tools plug into, emphasizing API access, custom fields, and workflow automation so each company can model its own onboarding, offboarding, and compensation processes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of Humaans is a people directory storing employee records, documents, absence and time-off data, and timesheets, paired with an org chart and headcount/compensation reporting. Automated workflows handle onboarding, offboarding, and compensation review processes, assigning tasks to HR, IT, and managers as employees move through their lifecycle.$q$, $q$Real-time insights and automated reports give People teams visibility into headcount, turnover, and compensation trends, and a rewards marketplace adds employee benefits on top of the core HRIS. More recently, Humaans launched 'Athena,' an agentic AI layer that lets teams build natural-language automations, triage HR requests, and connect pre-built AI agents to existing HRIS and ATS data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Humaans' entry tier, Starting Up, is priced around 7 dollars per seat per month and covers core people-data, document, and absence-tracking features for smaller teams. The Growth plan moves to custom, sales-assisted pricing and adds workflow automation, analytics, limited custom permission roles, and API/integration access.$q$, $q$The top-tier Enterprise plan is also custom-quoted and adds SAML single sign-on, unlimited custom fields and permission roles, webhooks, audit log exports, a dedicated sandbox environment, a named customer success manager, and an uptime SLA, aimed at larger or more security-conscious organizations.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('263780ad-dbb8-4862-b01a-e1ce95f8fa3a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
