INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Free and paid ticketing$q$, $q$Unlimited ticket types for both free and paid events at no signup cost.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Customizable event pages$q$, $q$Branded checkout and registration flows tailored to each event.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Seating and capacity management$q$, $q$Manage venue capacity, seating charts, and ticket allotments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Check-in app$q$, $q$Mobile check-in tools for scanning tickets and managing entry on event day.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Promo codes and discounting$q$, $q$Create discount codes and promotional pricing for ticket sales.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Embeddable widgets$q$, $q$Embed ticket purchasing directly into an organizer's own website.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Sales and attendance reporting$q$, $q$Dashboard analytics on ticket sales, revenue, and attendee data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Charitable impact reporting$q$, $q$Transparent public reporting on how booking-fee profit is donated to charity.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$100 percent of booking-fee profit goes to charity, mainly children's education programs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$No signup fees or long-term contracts for organizers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Discounted rates for registered non-profits and schools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Full-featured ticketing toolkit comparable to commercial platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Free events cost organizers nothing to run$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Smaller market presence and brand recognition than Eventbrite or Ticketmaster$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Booking fee is passed to the buyer by default, which some organizers may want to absorb instead$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Fewer large-venue and major touring-event integrations than dominant commercial competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Feature set, while solid, is less extensive than long-established enterprise ticketing platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Availability of local payment methods and currencies is more limited outside its core markets$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$What is Humanitix?$q$, $q$Humanitix is a not-for-profit online event ticketing platform, founded in Sydney in 2016, that donates 100 percent of the profit from its booking fees to charity, primarily education programs for disadvantaged children.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Who founded Humanitix?$q$, $q$Humanitix was founded in 2016 by Adam McCurdie and Joshua Ross in Sydney, Australia.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$How much does Humanitix cost to use?$q$, $q$It is free to run free events on Humanitix. For paid events, the platform charges a booking fee of 5 percent plus 1.29 dollars per ticket in the US, typically passed on to the buyer, with a discounted 3.9 percent plus 1.29 dollars rate for registered non-profits and schools.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Where does Humanitix's profit go?$q$, $q$Humanitix directs 100 percent of the profit generated from its booking fees to charitable causes, with a primary focus on education programs for children, having donated over 13.8 million dollars since 2016.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Where does Humanitix operate?$q$, $q$Humanitix is headquartered in Sydney, Australia, with additional offices in Auckland, Denver, and Edinburgh, and operates in Australia, New Zealand, the United States, and the United Kingdom.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$How does Humanitix compare to Eventbrite?$q$, $q$Humanitix offers comparable ticketing features to Eventbrite but is structured as a not-for-profit that donates its booking-fee profit to charity, whereas Eventbrite is a for-profit commercial platform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Community and charity events$q$, $q$Nonprofits and community organizers sell tickets at discounted rates while supporting a mission-aligned platform.$q$, $q$Nonprofits, schools, and community organizers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Live shows and touring performances$q$, $q$Artists and venues sell tickets for concerts and live performances with full checkout and seating tools.$q$, $q$Musicians, venues, and event promoters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Conferences and courses$q$, $q$Organizers manage registration, ticket types, and attendee check-in for professional conferences and educational courses.$q$, $q$Conference organizers and course providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Free Events$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited ticket types","No signup fees","Attendee data collection","Check-in app"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Paid Events (Standard)$q$, $q$5% + $1.29 per paid ticket$q$, $q$per ticket sold$q$, NULL, $q$["Unlimited ticket types","Customizable checkout","Reporting and analytics","Fee passed to buyer by default"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$Paid Events (Non-Profit / School Rate)$q$, $q$3.9% + $1.29 per paid ticket$q$, $q$per ticket sold$q$, NULL, $q$["Discounted rate for registered non-profits and schools","Same full feature set as standard paid plan"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Humanitix is a not-for-profit event ticketing platform founded in Sydney, Australia in 2016 by Adam McCurdie and Joshua Ross, built on the idea that the booking fees attendees already pay could fund charitable causes rather than generate private profit for a ticketing company. As a registered not-for-profit, Humanitix directs 100 percent of the profit from its booking fees to charity, with a primary focus on education programs for disadvantaged children.$q$, $q$By 2026 the organization reports having donated more than 13.8 million dollars to charitable causes since launch, and has expanded operations beyond Australia into New Zealand, the United States, and the United Kingdom, with offices in Sydney, Auckland, Denver, and Edinburgh. In 2026, actor Hugh Jackman joined Humanitix as Head of Impact, reflecting the organization's continued push to raise the profile of purpose-driven ticketing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Humanitix offers the standard toolkit expected of a modern ticketing platform: customizable event pages and checkout flows, unlimited ticket types for both free and paid events, seating and capacity management, promo codes, attendee data collection, and a check-in app for event day. Organizers can embed ticketing widgets directly into their own websites and access sales and attendance reporting through a dashboard.$q$, $q$The platform supports a range of event types, including live shows and touring performances, conferences, community and fundraising events, and courses, and requires no signup fee or long-term contract to get started.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$For free events, Humanitix costs organizers nothing at all -- there are no signup fees, subscription costs, or hidden charges. For paid ticketed events, Humanitix charges a booking fee of 5 percent plus 1.29 dollars per paid ticket in the United States, which by default is passed on to the ticket buyer rather than deducted from the organizer's revenue.$q$, $q$Registered non-profits and schools receive a discounted rate of 3.9 percent plus 1.29 dollars per paid ticket. Because 100 percent of the profit from these fees goes to charity, organizers who choose Humanitix are directly funding education and social-impact programs simply by using the platform they would otherwise pay a for-profit ticketing company for.$q$]::text[], 2);
