-- ── HubSpot CRM ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, unlimited-user CRM from HubSpot for managing contacts, deals, and pipelines with optional paid upgrades.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$10,000+ employees$q$, company_size),
  headquarters = COALESCE($q$Cambridge, Massachusetts, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$HubSpot CRM Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$HubSpot CRM review 2026: what the free plan includes, Starter/Professional/Enterprise pricing, key features, pros, cons, and top CRM alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HubSpot CRM is the free customer relationship management product at the core of the broader HubSpot customer platform, built by HubSpot Inc., which Brian Halligan and Dharmesh Shah founded in 2006 in Cambridge, Massachusetts after meeting at the MIT Sloan School of Management. HubSpot launched the CRM as a permanently free product in 2014, deliberately using it as a lead magnet: any business can create contact and company records, log deals through a visual pipeline, track emails, schedule meetings, use live chat and forms, and collaborate with unlimited users at zero cost, with the company instead monetizing premium marketing, sales, and service automation layered on top through paid 'Hubs.' Technically, HubSpot CRM sits on the same underlying object model and database as the rest of the HubSpot platform (Marketing Hub, Sales Hub, Service Hub, CMS Hub, and Operations Hub), which means upgrading later does not require a data migration -- contacts, deals, and activity history carry forward automatically. The free tier supports core CRM functions including a contact and deal timeline, task reminders, basic email templates and tracking, deal and ticket pipelines, and integration with Gmail and Outlook. Paid upgrades unlock progressively more automation and customization: Starter (roughly 15-20 dollars per seat per month) removes HubSpot branding, adds a small number of automated workflows, and increases the number of pipelines; Professional (around 100 dollars per seat per month as part of Sales Hub or Service Hub Professional) adds custom reporting, forecasting, playbooks, and more advanced sequence and automation limits; and Enterprise (from about 150 dollars per seat per month) adds custom objects, advanced permissions, sandboxes, and predictive lead scoring. HubSpot CRM's target audience is broad: solo founders and very small businesses that never need to pay anything, small sales teams that outgrow spreadsheets, and mid-market companies that use the free CRM as the entry point before adopting HubSpot's paid marketing or service tools. HubSpot is a public company (NYSE: HUBS) with more than 10,000 employees worldwide and a large partner ecosystem, giving the free CRM unusually deep documentation, onboarding support, and integration coverage (1,700+ App Marketplace listings) compared to most free CRM tools. Named competitors in the free/entry-level CRM category include Salesforce Starter, Zoho CRM's free tier, Freshsales, Pipedrive, and monday CRM; HubSpot CRM differentiates by pairing genuinely unlimited free users with the option to scale seamlessly into full marketing and service automation without switching vendors, whereas most competing free CRMs cap either users, contacts, or features far more aggressively or require an eventual platform migration to add marketing automation.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ef29f747-f15c-4d08-991c-1e5c8ee38641';

