-- ── Hubzilla ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, self-hosted, open-source platform for decentralized social networking, websites, file sharing, and wikis.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Hubzilla Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Hubzilla review 2026: what this open-source decentralized social platform does, the Zot protocol, self-hosting, pros, cons, and Fediverse alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Hubzilla is a free and open-source set of web applications that run on self-hosted servers called 'hubs,' which connect to each other in a decentralized federated network known as 'the grid.' It traces its lineage to Mistpark, a project Mike Macgirvin released in 2010, which evolved into Friendica; Macgirvin later left Friendica to experiment with a new decentralized identity and access-control framework, forking the codebase in 2012 first under the names Red and Red Matrix before the project was renamed Hubzilla. Macgirvin stepped down as active project coordinator in early 2015, handing management to the open-source community, though he continued contributing periodically and went on to found Zot Labs, the umbrella project home for Hubzilla and its Zot protocol. There is no company behind Hubzilla and no funding history in the traditional sense; it is community-maintained software distributed under the GNU Affero General Public License (AGPLv3), written primarily in PHP and JavaScript, with source code hosted on GitLab and GitHub. The defining technical innovation is the Zot protocol, a JSON-based framework for decentralized identity, communications, and fine-grained, extensible access control across independently operated hubs. Zot enables 'nomadic identity,' meaning a user's channel (their identity, content, and connections) can be cloned across multiple hubs rather than being locked to a single server, so if one hub goes offline or a user wants to migrate, their identity and social graph can move or be mirrored elsewhere without starting over -- a capability most other federated platforms, including Mastodon, do not offer. On top of this identity layer, Hubzilla functions simultaneously as a social network (streams, wall posts, comments, groups), a content management system for building full websites, a file and photo storage/sharing service, a forum and discussion-group host, a wiki and article-publishing system, and a calendar/events tool, all behind a single sign-on that works across every hub in the grid. For interoperability with the broader Fediverse, Hubzilla supports ActivityPub, Diaspora, DFRN, and OStatus protocols, allowing it to federate with Mastodon, Friendica, and other network software beyond hubs running Zot natively. Because Hubzilla is self-hosted, there is no official SaaS pricing; anyone can download and run it for free on their own server or VPS, and the practical cost is whatever hosting a small web server costs, typically a few dollars a month on a low-end VPS. Its target audience is technically inclined users, privacy-conscious communities, and organizations who want an alternative to centralized social platforms and are willing to self-host and administer their own server. Named alternatives and competitors in the federated/decentralized space include Mastodon (simpler, Twitter-like microblogging focus without nomadic identity), Friendica (its sibling project, more social-network-focused with fewer CMS/wiki features), Diaspora (an earlier decentralized social network), Pleroma/Akkoma (lightweight ActivityPub servers), and Nextcloud Social. Hubzilla differentiates from all of them primarily through its breadth -- combining social networking, CMS, file storage, and identity portability in one federated platform -- at the cost of a steeper learning curve and heavier server requirements than single-purpose Fediverse software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a66fca94-72b5-448d-a986-f5944ee873d8';

