-- ── Huly ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source all-in-one project management platform combining issue tracking, docs, chat, and video as a Linear and Notion alternative.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Huly Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Huly review 2026: open-source project management with issue tracking, chat, and docs, pricing tiers, self-hosting, pros, cons, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Huly is an open-source, all-in-one project management platform built by Hardcore Engineering Inc. as a self-described alternative to Linear, Jira, Slack, Notion, and Motion, aiming to replace several separate work tools with one connected workspace. The platform was founded by Andrey Platov, who serves as CEO, with Hardcore Engineering operating as a small, lean team of roughly a dozen to a few dozen engineers building the platform in the open. Huly combines an issue and task tracker with customizable workflows, a team planner offering a centralized calendar and time-blocking view, a knowledge base and document editor for collaborative writing, built-in instant messaging and group chat channels, and native audio/video conferencing rooms functioning as a 'virtual office,' all inside a single unified data model so switching between a task, a linked document, and a conversation about it does not require leaving the app. Integrations include GitHub (two-way issue and PR sync), Gmail, and Google Calendar, and Huly exposes its data model for further extension since the entire platform is open source. The Huly Platform is released under the commercially permissive EPL-2.0 license, with source code hosted publicly on GitHub under the hcengineering organization; technically it is built on a stack including CockroachDB, Elasticsearch, Redpanda, and MinIO, all containerized and deployable via Docker Compose for self-hosting, with documented minimum requirements of 2 vCPUs and 8 GB RAM (4+ vCPUs and 16 GB RAM recommended for production use). Because the platform is open source, self-hosting is entirely free and unlimited; Hardcore Engineering also historically offered a hosted cloud version, though the company has signaled that free hosted-cloud service is being wound down as it shifts focus, making self-hosting the primary path for teams that want the full platform without relying on the vendor's infrastructure. Where a managed offering is available, pricing follows a tiered structure: a free Common plan for individuals and small teams getting started (10 GB storage, 10 GB video/audio traffic), Rare at roughly 19.99 dollars per month flat rate (100 GB storage and video traffic, unlimited users and unlimited Huly objects), Epic at roughly 99.99 dollars per month for professional teams and small businesses (1 TB storage, 500 GB video traffic), and Legendary at roughly 399.99 dollars per month for large teams needing maximum capacity (10 TB storage, 2 TB video traffic). Huly's target audience is software development teams, startups, and product teams who want the functionality of Linear-style issue tracking plus Notion-style docs plus Slack-style chat without paying for and maintaining four or five separate SaaS subscriptions, as well as privacy- and cost-conscious organizations that prefer to self-host their tools. Named competitors and alternatives include Linear (sleeker, narrower issue tracker only), Jira (enterprise incumbent, heavier and more complex), Notion (docs/wiki-first, weaker native issue tracking), Monday.com and ClickUp (broader work-management suites, closed source), and ChatWoot/Rocket.Chat for the messaging component; Huly differentiates primarily by being fully open source and self-hostable while still covering the breadth of an all-in-one suite, which few of its closed-source competitors offer at any price.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9c31b644-e9f8-4a6c-b3aa-e7960053e0dc';

