-- ── Humaans ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Modern, AI-powered HRIS for managing employee data, onboarding, time off, and people workflows for growing teams.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Humaans Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Humaans review 2026: HRIS features, employee data management, onboarding automation, pricing tiers, pros, cons, and top HR software alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Humaans is a modern, cloud-based HR information system (HRIS) built for growing companies that need to centralize employee data and automate people-operations workflows without the complexity of legacy enterprise HR suites. It was founded in London in 2019 (with its funding and public growth phase accelerating from 2020-2021) by Giovanni Luperti, who serves as CEO, and Karolis Narkevicius; Luperti previously worked as Director of Product Design at Qubit before starting Humaans. The company is backed by venture funding, having raised a seed round in March 2021 and a Series A round later in 2021 worth roughly 12-13 million dollars, bringing total disclosed funding to around 20 million dollars across investors including participants in both rounds; Humaans was also part of Y Combinator. The company remains headquartered in London with roughly 40-50 employees. Architecturally, Humaans is built as a flexible, API-first system of record for employee data, emphasizing a consumer-grade user interface (a notable design differentiator versus older HR software) alongside deep configurability: custom fields, custom permission roles, and workflow automation builders let each company model onboarding, offboarding, compensation review, and other HR processes without needing custom development. Core functionality includes a central people directory with document management (storing contracts, IDs, and other employee files), absence and time-off tracking, timesheets, org chart visualization, headcount and compensation management and reporting, real-time analytics and automated reports, and a rewards/benefits marketplace. Onboarding and offboarding are handled through automated, triggerable workflows that assign tasks across HR, IT, and managers. In 2025-2026 Humaans introduced 'Athena,' an agentic AI layer with pre-built AI agents, natural-language workflow building, HRIS/ATS integrations, employee self-service request handling, and intelligent triaging of HR requests and approvals, reflecting a broader push to add AI automation on top of the core HRIS. The platform integrates with Google Workspace, Microsoft 365, Slack, Okta, DocuSign, Greenhouse, and Lattice, among others, and exposes a robust public API for custom integrations. Pricing is tiered: a 'Starting Up' entry plan around 7 dollars per seat per month for smaller teams with core people-data and absence features; a Growth plan (custom-quoted, typically requiring a sales conversation) adding workflow automation, insights/analytics, up to two custom permission roles, and integrations/API access; and an Enterprise plan (custom-quoted) that layers on SAML-based single sign-on including Okta and Entra ID, unlimited custom permission roles and fields, webhooks, audit log export, a dedicated sandbox, a dedicated customer success manager, and an SLA-backed 99.9% uptime guarantee. Humaans' target audience is HR and People teams at fast-growing startups and scale-ups, typically in the 50-1,000 employee range, who have outgrown spreadsheets or a barebones HR tool but do not want the implementation overhead of enterprise suites like Workday or SAP SuccessFactors. Named competitors include BambooHR and Personio (similar mid-market HRIS positioning), HiBob (another design-forward HR platform, particularly strong in Europe), Workday (enterprise-grade but heavier), and Deel/Rippling (broader HR-plus-payroll/IT platforms); Humaans differentiates through its emphasis on interface design, configurability without code, and API-first architecture aimed specifically at fast-moving people teams.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '263780ad-dbb8-4862-b01a-e1ce95f8fa3a';

