-- ── Humanitix ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Not-for-profit event ticketing platform that donates 100 percent of booking-fee profit to charity, mainly education for children.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Sydney, Australia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Humanitix Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Humanitix review 2026: nonprofit event ticketing features, booking fees, pricing, pros, cons, and how it compares to Eventbrite and other alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Humanitix is an Australian not-for-profit online event ticketing platform built on the premise that the booking fees attendees already pay to ticketing companies could fund charitable causes instead of generating private profit. It was founded in Sydney in 2016 by Adam McCurdie and Joshua Ross, who set out to redirect the same fees charged by conventional ticketing companies like Eventbrite toward social impact rather than shareholder returns. Structured as a not-for-profit organization, Humanitix directs 100 percent of the profit generated from its booking fees to charitable causes, with a primary focus on funding education programs for children in disadvantaged communities in Australia and internationally; by 2026 the platform reports having donated more than 13.8 million dollars to charity since its 2016 founding. In 2026 actor and producer Hugh Jackman joined Humanitix in the role of Head of Impact, adding public profile to the organization's mission-driven positioning. Humanitix has expanded beyond Australia to operate in New Zealand, the United States, and the United Kingdom, with a Sydney headquarters and additional offices in Auckland, Denver, and Edinburgh. Functionally, the platform offers the same core toolset as commercial event ticketing competitors: event creation and a customizable checkout/registration flow, unlimited ticket types for both free and paid events, seating and capacity management, promo codes and discounting, attendee data collection and communication tools, check-in apps for event day, embeddable widgets for organizer websites, and reporting/analytics on sales and attendance, all usable for live shows, conferences, fundraisers, community events, and courses. There are no signup fees and no long-term contracts, and for the majority of event organizers running free events, using Humanitix costs nothing at all. For paid ticketed events, Humanitix charges a booking fee of 5 percent plus 1.29 dollars per paid ticket in the United States (rates vary slightly by country), and by default this fee is passed on to the ticket buyer at checkout, meaning organizers keep 100 percent of their listed ticket price. Registered non-profit organizations and schools qualify for a reduced rate of 3.9 percent plus 1.29 dollars per paid ticket, reflecting the platform's mission-aligned pricing for mission-aligned organizers. Humanitix's target audience spans individual event hosts, community and charity organizers, universities, conference producers, and touring live-events promoters who want full-featured ticketing software but prefer their booking fees to fund social impact rather than enrich a for-profit ticketing company. Named competitors include Eventbrite (the dominant for-profit incumbent with similar feature depth but standard commercial fee structures), Ticketmaster and AXS (for larger venues and touring events), and TryBooking and Humanitix's fellow purpose-driven ticketing platforms; Humanitix differentiates almost entirely on its nonprofit structure and transparent, publicly reported charitable giving, while matching or approaching the feature parity of commercial platforms like Eventbrite on ticketing functionality itself.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f58d22a2-7e1d-4bb6-94f3-ba3ce32f636d';

